import React, { useEffect , useState, useRef} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import MeHeader from '../components/MeHeader'
import MeSidebar from '../components/MeSidebar'
import MeMessages from '../components/MeMessages'
import {useSelector} from 'react-redux'
import {accountSelector} from '../redux/accountSlice'
import {useNavigate} from 'react-router-dom'


const MePageWrapper = styled.div `
width:90%;
margin:0 auto;
`

const MeBody = styled.div `
display:flex;
justify-content:center;
align-items:flex-start;
width:100%;
margin-top:30px;
`

const RightBodyPart = styled.div `
width:100%;

`




export default function Me () {
	const account = useSelector(accountSelector)
	const navigate = useNavigate()
	const sidebarRef = useRef('')
	const [sidebarState, setSidebarState] = useState([])


	const sidebar = (data) => {
		sidebarRef.current = data
		console.log(sidebarRef.current)
	}

	const onSidebarClick = () => {
		setSidebarState(sidebarRef.current)
	}

	return (
		<>
			{account.isLogin ? null : navigate('/')}
			<Header />
			<Navbar />
			<MePageWrapper>
				<MeHeader/>
				<MeBody>
					{console.log(sidebarState)}
					<MeSidebar sidebar={sidebar} onClick={onSidebarClick}/>
					<RightBodyPart>
						{sidebarState.messageActive ? <MeMessages/> : null}
						{sidebarState.myItemsActive ? <div>123</div> : null}
					</RightBodyPart>
				</MeBody>
			</MePageWrapper>
		</>
	)
}
